{
  "grammar": [
    {
      "pattern": "房間 + 有 + facility",
      "structure": ["room", "有", "facility"],
      "explanation_en": "Use 有 to state that a room or apartment has a certain facility or feature.",
      "title": "有 for Facility Existence",
      "meaning": "A room/apartment has [facility].",
      "when_to_use": ["Describing what facilities are in a room or apartment", "Listing features of a place"],
      "when_not_to_use": ["When describing location of an object (use 在 instead)", "When talking about possession of personal items"],
      "pragmatic_notes": "In Taiwan, when describing an apartment, it's common to list facilities like 冷氣, 洗衣機, 網路. Use 有 to confirm availability.",
      "word_order_notes": "Place the room/location first, then 有, then the facility. No measure word needed for general existence.",
      "english_contrast": "English says 'The room has air conditioning.' Chinese uses the same structure: 房間有冷氣.",
      "korean_contrast": "Korean uses '에는/에는 + 이/가 있다' structure. Chinese is simpler: just 有.",
      "negative_examples": [
        {
          "text": "冷氣有房間。",
          "error": "Wrong word order: facility should come after 有, not before."
        }
      ],
      "incorrect_examples": [
        {
          "text": "房間有一個冷氣。",
          "error": "Using 一個 is unnecessary for general existence; just say 有冷氣."
        }
      ],
      "transformation_drills": ["Change '房間有冷氣' to negative: '房間沒有冷氣'", "Change '客廳有沙發' to question: '客廳有沙發嗎?'"],
      "production_drills": ["Describe your own room using 有: '我的房間有床和桌子。'", "Ask a partner: '你的公寓有什麼？'"],
      "common_error_patterns": ["Putting facility before 有", "Adding unnecessary measure words"],
      "repair_feedback": {
        "word_order": "Remember: room first, then 有, then facility.",
        "politeness": "This structure is neutral; no special politeness needed.",
        "vocabulary": "Use facility words like 冷氣, 冰箱, 網路."
      }
    },
    {
      "pattern": "facility + 在 + location",
      "structure": ["facility", "在", "location"],
      "explanation_en": "Use 在 to state where a facility is located within a room or apartment.",
      "title": "在 for Location of Facility",
      "meaning": "The [facility] is at [location].",
      "when_to_use": ["Pointing out where a specific facility is", "Describing the layout of a room"],
      "when_not_to_use": ["When stating existence of a facility (use 有 instead)", "When talking about people's location"],
      "pragmatic_notes": "In Taiwan, when showing an apartment, you might say '冷氣在客廳' or '洗衣機在陽台'.",
      "word_order_notes": "Facility comes first, then 在, then the location. This is opposite to English word order.",
      "english_contrast": "English says 'The air conditioner is in the living room.' Chinese says '冷氣在客廳' (facility + 在 + location).",
      "korean_contrast": "Korean uses '에 있다' after location. Chinese puts location after 在.",
      "negative_examples": [
        {
          "text": "在客廳冷氣。",
          "error": "Wrong order: facility must come before 在."
        }
      ],
      "incorrect_examples": [
        {
          "text": "冷氣有在客廳。",
          "error": "Do not use 有 with 在 for location; just say 冷氣在客廳."
        }
      ],
      "transformation_drills": ["Change '冷氣在客廳' to question: '冷氣在哪裡？'", "Change '洗衣機在陽台' to negative: '洗衣機不在陽台'"],
      "production_drills": ["Describe where facilities are in your apartment: '冰箱在廚房。'", "Ask a partner: '你的書桌在哪裡？'"],
      "common_error_patterns": ["Using 有 with 在", "Putting location before facility"],
      "repair_feedback": {
        "word_order": "Facility first, then 在, then location.",
        "politeness": "Neutral structure; no special politeness needed.",
        "vocabulary": "Use location words like 客廳, 廚房, 陽台."
      }
    },
    {
      "pattern": "facility + 壞掉了",
      "structure": ["facility", "壞掉了"],
      "explanation_en": "Use 壞掉了 to indicate that a facility is broken or not working.",
      "title": "壞掉了 for Broken Facility",
      "meaning": "[Facility] is broken.",
      "when_to_use": ["Reporting a problem with a facility", "Complaining to a landlord or repair person"],
      "when_not_to_use": ["When the facility is just old but working", "When describing a temporary issue like power outage"],
      "pragmatic_notes": "In Taiwan, when something breaks, you say '壞掉了' to the landlord. It's common to add '要修理' (needs repair).",
      "word_order_notes": "Facility comes first, then 壞掉了. No need for 是 or 了 after 壞掉.",
      "english_contrast": "English says 'The air conditioner is broken.' Chinese says '冷氣壞掉了.'",
      "korean_contrast": "Korean uses '고장났어요' after the facility. Chinese uses 壞掉了.",
      "negative_examples": [
        {
          "text": "壞掉了冷氣。",
          "error": "Wrong order: facility must come before 壞掉了."
        }
      ],
      "incorrect_examples": [
        {
          "text": "冷氣是壞掉了。",
          "error": "Do not use 是 with 壞掉了; just say 冷氣壞掉了."
        }
      ],
      "transformation_drills": ["Change '冷氣壞掉了' to question: '冷氣壞掉了嗎？'", "Change '冰箱壞掉了' to negative: '冰箱沒有壞掉'"],
      "production_drills": ["Report a problem: '熱水器壞掉了。'", "Ask a partner: '你的房間有什麼壞掉了？'"],
      "common_error_patterns": ["Putting 壞掉了 before facility", "Adding 是 unnecessarily"],
      "repair_feedback": {
        "word_order": "Facility first, then 壞掉了.",
        "politeness": "Use 不好意思 before reporting to be polite: '不好意思，冷氣壞掉了。'",
        "vocabulary": "Use facility words like 冷氣, 熱水器, 馬桶."
      }
    }
  ]
}
